/*
 * DROP PROC dbo.INSERT_TSECTIONDYNVAL
 */
IF OBJECT_ID('dbo.INSERT_TSECTIONDYNVAL') IS NOT NULL
BEGIN
    DROP PROC dbo.INSERT_TSECTIONDYNVAL
    PRINT '<<< DROPPED PROC dbo.INSERT_TSECTIONDYNVAL >>>'
END

GO


--=============================
--  DEBUT CREATION PROCEDURE
--=============================
CREATE PROCEDURE INSERT_TSECTIONDYNVAL (     @CTR_NF       UCTR_NF,
                                             @SEC_NF       tinyint
					             )
AS

DECLARE      @erreur         int,
             @trans_etat     int,
             @p_CTR_NF       UCTR_NF,
             @p_SEC_NF       tinyint,
             @p_UWY_NF       UUWY_NF

PRINT 'INSERTION <%1!><%2!>', @CTR_NF, @SEC_NF

SELECT TOP 1 CTR_NF, SEC_NF, UWY_NF INTO #tmp_liste_section FROM BTRT..TSECTION
DELETE FROM #tmp_liste_section

INSERT INTO #tmp_liste_section (CTR_NF, SEC_NF, UWY_NF)
SELECT CTR_NF, SEC_NF, UWY_NF  FROM BTRT..TSECTION WHERE
        CTR_NF = @CTR_NF
AND SEC_NF = @SEC_NF

BEGIN TRAN

DECLARE LOOP_SECTION CURSOR FOR
           SELECT CTR_NF, SEC_NF, UWY_NF FROM #tmp_liste_section
           
if @@error!=0
BEGIN
     PRINT 'ERREUR CREATION CURSOR - MAJ <%2!><%3!> - ERREUR : %1!',@@error , @CTR_NF, @SEC_NF
     ROLLBACK TRAN
     GOTO fin
END

OPEN LOOP_SECTION

fetch LOOP_SECTION into
			@p_CTR_NF , @p_SEC_NF , @p_UWY_NF
			IF (@@sqlstatus = 1)
					BEGIN
                    PRINT "ERREUR LOOP_SECTION CURSOR"
                    CLOSE LOOP_SECTION
                    RETURN
          END
      WHILE (@@sqlstatus != 2)
          BEGIN
          	        IF EXISTS (SELECT 1 FROM BTRT..TSECTIONDYNVAL WHERE CTR_NF = @p_CTR_NF AND SEC_NF = @p_SEC_NF AND UWY_NF = @p_UWY_NF AND DYNFIELD_CT = 36 )
          	        BEGIN
          	             fetch LOOP_SECTION into  @p_CTR_NF , @p_SEC_NF , @p_UWY_NF
          	        END
          	        ELSE
          	        BEGIN
                         INSERT INTO BTRT..TSECTIONDYNVAL (CTR_NF,UWY_NF,UW_NT,END_NT,SEC_NF,DYNFIELD_CT,FIELDVAL_M,FIELDVAL_B,FIELDVAL_D,FIELDVAL_LL,COLVAL_CT,CREUSR_CF,CRE_D,LSTUPDUSR_CF,LSTUPD_D) 
                         VALUES (@p_CTR_NF,@p_UWY_NF,1,0,@p_SEC_NF,36,null,1,null,null,null,'INF7',getdate(),'INF7',getdate()) 
                         fetch LOOP_SECTION into  @p_CTR_NF , @p_SEC_NF , @p_UWY_NF
                    END
          END

CLOSE LOOP_SECTION
DEALLOCATE CURSOR LOOP_SECTION


 -- récuperer codes retour et nb lignes impactées --
SELECT @erreur = @@error, @trans_etat = @@transtate

IF @erreur != 0 OR @trans_etat > 1
BEGIN
     PRINT 'ERREUR INSERTION - MAJ <%2!><%3!> - ERREUR : %1!',@erreur, @CTR_NF, @SEC_NF
     ROLLBACK TRAN
     GOTO fin
END

PRINT 'FIN INSERTION <%1!><%2!>', @CTR_NF, @SEC_NF
 -- ------------------- --
-- Fin transaction     --
-- ------------------- --
COMMIT TRAN
fin:


IF OBJECT_ID('dbo.INSERT_TSECTIONDYNVAL') IS NOT NULL
    PRINT '<<< CREATED PROC dbo.INSERT_TSECTIONDYNVAL >>>'
ELSE
    PRINT '<<< FAILED CREATING PROC dbo.INSERT_TSECTIONDYNVAL >>>'
go

--=============================
--  FIN CREATION PROCEDURE
--=============================

